#include <stdio.h>
#include <stdlib.h>
#define MAX 100
int main() {
    int n;
    scanf("%d", &n);
    int matrix[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            scanf("%d", &matrix[i][j]);
        }
    }
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (matrix[i][j] != i * n + j + 1) {
                count++;
            }
        }
    }
    printf("%d\n", count);
    return 0;
}

