code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let matrix = [];
let count = 0;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        matrix.push(input.split(' ').map(Number));
        if (matrix.length === n) {
            for (let i = 0; i < n; i++) {
                for (let j = 0; j < n; j++) {
                    if (matrix[i][j] !== i * n + j + 1) {
                        count++;
                    }
                }
            }
            console.log(count);
            rl.close();
        }
    }
});
